  public List<byte> PREVIOUS_MESSAGE_HASH { get; set; }
  public List<byte> PROVIDER_SIGNATURE { get; set; }

  public FSMT() {
    this.MESSAGE_ID = null;
    this.PROVIDER_PEER_ID = null;
    this.LISTING_ID = null;
    this.STREAM_ID = null;
    this.SCHEMA_CODE = null;
    this.SCHEMA_HASH = null;
    this.POLICY_ID = null;
    this.POLICY_VERSION = 1;
    this.KEY_EPOCH = null;
    this.SEQUENCE = 0;
    this.PRODUCED_AT = 0;
    this.EXPIRES_AT = 0;
    this.SUBJECT_ID = null;
    this.FIELDS = null;
    this.PAYLOAD_HASH = null;
    this.PREVIOUS_MESSAGE_HASH = null;
    this.PROVIDER_SIGNATURE = null;
  }
  public static FSMT DeserializeFromBinary(byte[] fbBuffer) {
    return FSM.GetRootAsFSM(new ByteBuffer(fbBuffer)).UnPack();
  }
  public byte[] SerializeToBinary() {
    var fbb = new FlatBufferBuilder(0x10000);
    FSM.FinishFSMBuffer(fbb, FSM.Pack(fbb, this));
    return fbb.DataBuffer.ToSizedArray();
  }
}


static public class FSMVerify
{
  static public bool Verify(Google.FlatBuffers.Verifier verifier, uint tablePos)
  {
    return verifier.VerifyTableStart(tablePos)
      && verifier.VerifyString(tablePos, 4 /*MESSAGE_ID*/, true)
      && verifier.VerifyString(tablePos, 6 /*PROVIDER_PEER_ID*/, true)
      && verifier.VerifyString(tablePos, 8 /*LISTING_ID*/, true)
      && verifier.VerifyString(tablePos, 10 /*STREAM_ID*/, true)
      && verifier.VerifyString(tablePos, 12 /*SCHEMA_CODE*/, true)
      && verifier.VerifyVectorOfData(tablePos, 14 /*SCHEMA_HASH*/, 1 /*byte*/, false)
      && verifier.VerifyString(tablePos, 16 /*POLICY_ID*/, true)
      && verifier.VerifyField(tablePos, 18 /*POLICY_VERSION*/, 4 /*uint*/, 4, false)
      && verifier.VerifyString(tablePos, 20 /*KEY_EPOCH*/, false)
      && verifier.VerifyField(tablePos, 22 /*SEQUENCE*/, 8 /*ulong*/, 8, false)
      && verifier.VerifyField(tablePos, 24 /*PRODUCED_AT*/, 8 /*ulong*/, 8, false)
      && verifier.VerifyField(tablePos, 26 /*EXPIRES_AT*/, 8 /*ulong*/, 8, false)
      && verifier.VerifyString(tablePos, 28 /*SUBJECT_ID*/, false)
      && verifier.VerifyVectorOfTables(tablePos, 30 /*FIELDS*/, FieldStreamValueVerify.Verify, false)
      && verifier.VerifyVectorOfData(tablePos, 32 /*PAYLOAD_HASH*/, 1 /*byte*/, false)
      && verifier.VerifyVectorOfData(tablePos, 34 /*PREVIOUS_MESSAGE_HASH*/, 1 /*byte*/, false)
      && verifier.VerifyVectorOfData(tablePos, 36 /*PROVIDER_SIGNATURE*/, 1 /*byte*/, false)
      && verifier.VerifyTableEnd(tablePos);
  }
}
